import React, { useEffect, useState } from "react";
import axios from "axios";
import "bootstrap/dist/css/bootstrap.min.css";
import Pagination from "../components/Pagination";

// Configuración de URL dinámica
const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000";

export default function VentasHistorial() {
  const [ventas, setVentas] = useState([]);
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10; 

  useEffect(() => {
    cargarHistorial();
  }, []);

  const cargarHistorial = async () => {
    try {
      setLoading(true);
      // Usamos la ruta configurada en tu index.js
      const res = await axios.get(`${API_URL}/api/ventas/historial`);
      setVentas(res.data);
    } catch (error) {
      console.error("❌ Error al cargar historial:", error);
    } finally {
      setLoading(false);
    }
  };

  // Lógica de Paginación
  const indexLast = currentPage * itemsPerPage;
  const indexFirst = indexLast - itemsPerPage;
  const ventasMostradas = ventas.slice(indexFirst, indexLast);

  if (loading) {
    return (
      <div className="container mt-5 text-center">
        <div className="spinner-border text-primary" role="status"></div>
        <p className="mt-2">Cargando historial de ventas...</p>
      </div>
    );
  }

  return (
    <div className="container mt-4 pb-5">
      <div className="d-flex justify-content-between align-items-center mb-3">
        <h3 className="fw-bold text-primary">📊 Historial de Ventas</h3>
        <button className="btn btn-outline-secondary btn-sm" onClick={cargarHistorial}>
          🔄 Actualizar
        </button>
      </div>

      <div className="card shadow-sm border-0">
        <div className="table-responsive">
          <table className="table table-hover align-middle mb-0 text-center">
            <thead className="table-dark">
              <tr>
                <th>Factura #</th>
                <th>Fecha y Hora</th>
                <th>Cliente</th>
                <th>Subtotal</th>
                <th>IVA (12%)</th>
                <th>Total</th>
              </tr>
            </thead>
            <tbody>
              {ventasMostradas.length > 0 ? (
                ventasMostradas.map((v) => (
                  <tr key={v.VentaID}>
                    <td className="fw-bold text-secondary">
                      {v.NumeroSecuencia?.toString().padStart(6, '0')}
                    </td>
                    <td>{new Date(v.Fecha).toLocaleString()}</td>
                    <td>{v.Cliente || "Cliente General"}</td>
                    {/* Convertimos a Number() porque Postgres devuelve decimales como strings */}
                    <td>${Number(v.Subtotal).toFixed(2)}</td>
                    <td>${Number(v.IVA).toFixed(2)}</td>
                    <td className="fw-bold text-success">
                        ${Number(v.Total).toFixed(2)}
                    </td>
                  </tr>
                ))
              ) : (
                <tr>
                  <td colSpan="6" className="py-5 text-muted">
                    No hay ventas registradas en el sistema.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="d-flex justify-content-center mt-4">
        <Pagination
          totalItems={ventas.length}
          itemsPerPage={itemsPerPage}
          currentPage={currentPage}
          onPageChange={setCurrentPage}
        />
      </div>
    </div>
  );
}
